import { useEffect, useState } from 'react';
import { accountingService } from '../services/accounting/accountingService';
import type { AccountingPeriodDateGate } from '../utils/accountingPeriodDateValidation';

/** Load kỳ kế toán — dùng validate khi Lưu (BR-001). */
export function useAccountingPeriods(): AccountingPeriodDateGate[] {
  const [periods, setPeriods] = useState<AccountingPeriodDateGate[]>([]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      accountingService.getPeriods()
        .then(rows => {
          if (cancelled) return;
          setPeriods(rows.map(p => ({ year: p.year, month: p.month, status: p.status })));
        })
        .catch(() => { /* BE validates on save */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  return periods;
}
